NP_functionality.VERILOG_PROVIDED:
reg waiting_state;
wire waiting_state_next;
reg flush_reg;
reg done_reg;
wire done_reg_next;
reg M_DataRdy_reg_old;
wire M_DataRdy_reg;
reg M_back_pressure_reg_old;
reg [BITSIZE_M_Rdata_ram -1 : 0] M_Rdata_ram_reg_old;
wire [BITSIZE_M_Rdata_ram -1 : 0] M_Rdata_ram_reg;
reg [BITSIZE_Mout_addr_ram -1 : 0] Mout_addr_ram_reg_old;
wire [BITSIZE_Mout_addr_ram -1 : 0] Mout_addr_ram_reg;
reg [BITSIZE_Mout_Wdata_ram -1 : 0] Mout_Wdata_ram_reg_old;
wire [BITSIZE_Mout_Wdata_ram -1 : 0] Mout_Wdata_ram_reg;
reg [BITSIZE_Mout_data_ram_size -1 : 0] Mout_data_ram_size_reg_old;
wire [BITSIZE_Mout_data_ram_size -1 : 0] Mout_data_ram_size_reg;
reg [BITSIZE_Mout_tag -1 :0] Mout_tag_reg;
wire [BITSIZE_Mout_tag -1 :0] Mout_tag_reg_next;

always @(posedge clock) 
begin
  if(1RESET_VALUE)
  begin
    waiting_state <= 0;
    flush_reg <= 0;
    done_reg <= 0;
    Mout_tag_reg <= 0;
    Mout_addr_ram_reg_old <= 0;
    Mout_Wdata_ram_reg_old <= 0;
    Mout_data_ram_size_reg_old <= 0;
    M_DataRdy_reg_old <= 0;
    M_Rdata_ram_reg_old <= 0;
    M_back_pressure_reg_old <= 0;
  end
  else
  begin
    waiting_state <= waiting_state_next;
    flush_reg <= dirty;
    done_reg <= done_reg_next;
    Mout_tag_reg <= Mout_tag_reg_next;
    Mout_addr_ram_reg_old <= Mout_addr_ram_reg;
    Mout_Wdata_ram_reg_old <= Mout_Wdata_ram_reg;
    Mout_data_ram_size_reg_old <= Mout_data_ram_size_reg;
    M_DataRdy_reg_old <= M_DataRdy_reg;
    M_Rdata_ram_reg_old <= M_Rdata_ram_reg;
    M_back_pressure_reg_old <= M_back_pressure;
  end 
end

assign flush = flush_reg && done_reg;
assign done = done_reg && !dirty;
assign done_reg_next = done_input || (done_reg && dirty);
assign waiting_state_next = (waiting_state && !ready) || (!waiting_state && (Mout_oe_ram || Mout_we_ram) && !M_back_pressure);

assign M_tag = Mout_tag_reg;
assign M_Rdata_ram = M_DataRdy_reg ? M_Rdata_ram_reg : {BITSIZE_M_Rdata_ram{1'b0}};
assign M_DataRdy = M_DataRdy_reg;

assign Mout_tag_reg_next = (M_back_pressure || (waiting_state && !ready)) ? Mout_tag_reg : Mout_tag;
assign M_DataRdy_reg = M_back_pressure_reg_old ? M_DataRdy_reg_old : ready;
assign M_Rdata_ram_reg = M_back_pressure_reg_old ? M_Rdata_ram_reg_old : rdata;

assign Mout_addr_ram_reg = (waiting_state && !ready) ? Mout_addr_ram_reg_old : Mout_addr_ram;
assign Mout_Wdata_ram_reg = (waiting_state && !ready) ? Mout_Wdata_ram_reg_old : Mout_Wdata_ram;
assign Mout_data_ram_size_reg = (waiting_state && !ready) ? Mout_data_ram_size_reg_old :  Mout_data_ram_size;

assign addr = Mout_addr_ram_reg[BITSIZE_Mout_addr_ram - 1:$clog2(BITSIZE_Mout_Wdata_ram / 8)];
assign wdata = Mout_Wdata_ram_reg;
assign valid = (Mout_oe_ram || Mout_we_ram) && !M_back_pressure && (!waiting_state || (waiting_state && ready));
assign wstrb = {BITSIZE_wstrb{Mout_we_ram}} & ((1 << (Mout_data_ram_size_reg >> 3)) - 1);
assign Mout_back_pressure = M_back_pressure | ((Mout_oe_ram || Mout_we_ram) && waiting_state);

assign m_axi_arlen = 0;
assign m_axi_arburst = BURST_TYPE;
assign m_axi_arlock = 0;
assign m_axi_arcache = 0;
assign m_axi_arprot = 0;
assign m_axi_arqos = 0;
assign m_axi_awlen = 0;
assign m_axi_awburst = BURST_TYPE;
assign m_axi_awlock = 0;
assign m_axi_awcache = 0;
assign m_axi_awprot = 0;
assign m_axi_awqos = 0;
assign m_axi_wlast = 1;

`ifndef _SIM_HAVE_CLOG2
  `define CLOG2(x) \
    (x <= 2) ? 1 : \
    (x <= 4) ? 2 : \
    (x <= 8) ? 3 : \
    (x <= 16) ? 4 : \
    (x <= 32) ? 5 : \
    (x <= 64) ? 6 : \
    (x <= 128) ? 7 : \
    -1
`endif

wire [2:0] size_next;

generate
  `ifdef _SIM_HAVE_CLOG2
    assign size_next = $clog2(Mout_data_ram_size >> 3);
  `else
    assign size_next = `CLOG2(Mout_data_ram_size >> 3);
  `endif
endgenerate

reg Mout_back_pressure_reg;
reg double_answer_first;
wire double_answer_first_next;
reg double_answer_second;
wire double_answer_second_next;

reg m_axi_awvalid_reg, m_axi_awvalid_next;
reg m_axi_wvalid_reg, m_axi_wvalid_next;
reg m_axi_arvalid_reg, m_axi_arvalid_next;

always @(*)
begin
  Mout_back_pressure_reg = 0;
  if(m_axi_awvalid_reg && !m_axi_awready)
  begin
    Mout_back_pressure_reg = 1;
  end
  else if(m_axi_wvalid_reg && !m_axi_wready)
  begin
    Mout_back_pressure_reg = 1;
  end
  else if(m_axi_arvalid_reg && !m_axi_arready)
  begin
    Mout_back_pressure_reg = 1;
  end
end

assign Mout_back_pressure = Mout_back_pressure_reg;

reg M_back_pressure_old;
reg [BITSIZE_M_tag-1:0] m_axi_bid_reg;
wire [BITSIZE_M_tag-1:0] m_axi_bid_reg_next;
reg [BITSIZE_M_tag-1:0] m_axi_rid_reg;
wire [BITSIZE_M_tag-1:0] m_axi_rid_reg_next;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    M_back_pressure_old <= 0;
  end
  else
  begin
    M_back_pressure_old <= M_back_pressure;
  end
end

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    m_axi_bid_reg <= 0;
    m_axi_rid_reg <= 0;
  end
  else
  begin
    m_axi_bid_reg <= m_axi_bid_reg_next;
    m_axi_rid_reg <= m_axi_rid_reg_next;
  end
end

assign m_axi_bid_reg_next = (m_axi_bvalid && m_axi_bready) ? m_axi_bid : m_axi_bid_reg;
assign m_axi_rid_reg_next = (m_axi_rvalid && m_axi_rready) ? m_axi_rid : m_axi_rid_reg;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    m_axi_awvalid_reg <= 0;
    m_axi_wvalid_reg <= 0;
  end
  else 
  begin
    m_axi_awvalid_reg <= m_axi_awvalid_next;
    m_axi_wvalid_reg <= m_axi_wvalid_next;
  end 
end

always @(*)
begin
  m_axi_awvalid_next = m_axi_awvalid_reg;
  m_axi_wvalid_next = m_axi_wvalid_reg;
  if(Mout_we_ram && !Mout_back_pressure_reg)
  begin
    m_axi_awvalid_next = 1;
    m_axi_wvalid_next = 1;
  end
  else
  begin
    if(m_axi_awready)
    begin
      m_axi_awvalid_next = 0;  
    end
    if(m_axi_wready)
    begin
      m_axi_wvalid_next = 0;  
    end
  end
end

assign m_axi_wvalid = m_axi_wvalid_reg;
assign m_axi_awvalid = m_axi_awvalid_reg;

reg [BITSIZE_Mout_Wdata_ram-1:0] m_axi_wdata_reg, m_axi_wdata_next;
reg [BITSIZE_m_axi_wstrb-1:0] m_axi_wstrb_reg, m_axi_wstrb_next;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    m_axi_wdata_reg <= 0;
    m_axi_wstrb_reg <= 0;
  end
  else
  begin
    m_axi_wdata_reg <= m_axi_wdata_next;
    m_axi_wstrb_reg <= m_axi_wstrb_next;
  end
end

always @(*)
begin
  m_axi_wdata_next = m_axi_wdata_reg;
  m_axi_wstrb_next = m_axi_wstrb_reg;
  if(Mout_we_ram && (!m_axi_wvalid_reg || m_axi_wready))
  begin
    m_axi_wdata_next = Mout_Wdata_ram;
    m_axi_wstrb_next = ((1 << (Mout_data_ram_size >> 3)) - 1);
  end
end

assign m_axi_wdata = m_axi_wdata_reg; 
assign m_axi_wstrb = m_axi_wstrb_reg;

reg [BITSIZE_m_axi_awaddr-1:0] m_axi_awaddr_reg, m_axi_awaddr_next;
reg [BITSIZE_m_axi_awsize-1:0] m_axi_awsize_reg, m_axi_awsize_next;
reg [BITSIZE_m_axi_awid-1:0] m_axi_awid_reg, m_axi_awid_next;


always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    m_axi_awaddr_reg <= 0;
    m_axi_awid_reg <= 0;
    m_axi_awsize_reg <= 0;
  end
  else
  begin
    m_axi_awaddr_reg <= m_axi_awaddr_next;
    m_axi_awid_reg <= m_axi_awid_next;
    m_axi_awsize_reg <= m_axi_awsize_next;
  end
end

always @(*)
begin
  if(Mout_we_ram && (!m_axi_awvalid_reg || m_axi_awready))
  begin
    m_axi_awaddr_next = Mout_addr_ram;
    m_axi_awid_next = Mout_tag;
    m_axi_awsize_next = size_next;
  end
  else
  begin
    m_axi_awaddr_next = m_axi_awaddr_reg;
    m_axi_awid_next = m_axi_awid_reg;
    m_axi_awsize_next = m_axi_awsize_reg;
  end
end

assign m_axi_awaddr = m_axi_awaddr_reg;
assign m_axi_awid = m_axi_awid_reg;
assign m_axi_awsize = m_axi_awsize_reg;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    m_axi_arvalid_reg <= 0;
  end
  else 
  begin
    m_axi_arvalid_reg <= m_axi_arvalid_next;
  end 
end

always @(*)
begin
  m_axi_arvalid_next = m_axi_arvalid_reg;
  if(Mout_oe_ram && !Mout_back_pressure_reg)
  begin
    m_axi_arvalid_next = 1;
  end
  else if(m_axi_arready)
  begin
    m_axi_arvalid_next = 0;  
  end
end

assign m_axi_arvalid = m_axi_arvalid_reg;

reg [BITSIZE_m_axi_araddr-1:0] m_axi_araddr_reg, m_axi_araddr_next;
reg [BITSIZE_m_axi_arsize-1:0] m_axi_arsize_reg, m_axi_arsize_next;
reg [BITSIZE_m_axi_awid-1:0] m_axi_arid_reg, m_axi_arid_next;


always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    m_axi_araddr_reg <= 0;
    m_axi_arid_reg <= 0;
    m_axi_arsize_reg <= 0;
  end
  else
  begin
    m_axi_araddr_reg <= m_axi_araddr_next;
    m_axi_arid_reg <= m_axi_arid_next;
    m_axi_arsize_reg <= m_axi_arsize_next;
  end
end

always @(*)
begin
  m_axi_araddr_next = m_axi_araddr_reg;
  m_axi_arid_next = m_axi_arid_reg;
  m_axi_arsize_next = m_axi_arsize_reg;
  if(Mout_oe_ram && (!m_axi_arvalid_reg || m_axi_arready))
  begin
    m_axi_araddr_next = Mout_addr_ram;
    m_axi_arid_next = Mout_tag;
    m_axi_arsize_next = size_next;
  end
end

assign m_axi_araddr = m_axi_araddr_reg;
assign m_axi_arid = m_axi_arid_reg;
assign m_axi_arsize = m_axi_arsize_reg;

reg M_DataRdy_reg;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    M_DataRdy_reg <= 0;
  end
  else
  begin
    M_DataRdy_reg <= M_back_pressure || double_answer_first_next || double_answer_second_next;
  end
end

assign M_DataRdy = (m_axi_bvalid && m_axi_bready) || (m_axi_rvalid && m_axi_rready) || M_DataRdy_reg;

reg [BITSIZE_M_Rdata_ram-1:0] M_Rdata_ram_reg;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    M_Rdata_ram_reg <= 0;
  end
  else 
  begin
    M_Rdata_ram_reg <= M_Rdata_ram;
  end
end


assign M_Rdata_ram = m_axi_rvalid & m_axi_rready ? m_axi_rdata : M_Rdata_ram_reg;

reg m_axi_bready_reg;
reg m_axi_rready_reg;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    m_axi_rready_reg <= 0;
    m_axi_bready_reg <= 0;
  end
  else if(M_back_pressure)
  begin
    m_axi_rready_reg <= 0;
    m_axi_bready_reg <= 0;
  end
  else if(double_answer_first_next || double_answer_second_next)
  begin
    m_axi_bready_reg <= 0;
    m_axi_rready_reg <= 0;
  end
  else
  begin
    m_axi_rready_reg <= 1;
    m_axi_bready_reg <= 1;
  end
end

assign m_axi_bready = m_axi_bready_reg;
assign m_axi_rready = m_axi_rready_reg;

reg [BITSIZE_M_tag-1:0] M_tag_reg, M_tag_next;

always @(posedge clock 1RESET_EDGE)
begin
  if(1RESET_VALUE)
  begin
    M_tag_reg <= 0;
    double_answer_first <= 0;
    double_answer_second <= 0;
  end
  else
  begin
    M_tag_reg <= M_tag_next;
    double_answer_first <= double_answer_first_next; 
    double_answer_second <= double_answer_second_next;   
  end
end

assign double_answer_first_next = (M_back_pressure && (m_axi_rready && m_axi_rvalid && m_axi_bready && m_axi_bvalid)) || (M_back_pressure && double_answer_first);
assign double_answer_second_next = (m_axi_rready && m_axi_rvalid && m_axi_bready && m_axi_bvalid) || (!double_answer_first_next && double_answer_first) || (M_back_pressure && double_answer_second);

always @(*)
begin
  if(M_back_pressure_old)
  begin
    M_tag_next = M_tag_reg;
  end
  else if(double_answer_first)
  begin
    M_tag_next = m_axi_rid_reg;
  end
  else if(double_answer_second)
  begin
    M_tag_next = m_axi_bid_reg;
  end
  else if(m_axi_rvalid && m_axi_rready)
  begin
    M_tag_next = m_axi_rid;
  end
  else if(m_axi_bvalid && m_axi_bready)
  begin
    M_tag_next = m_axi_bid;
  end
  else
  begin
    M_tag_next = 0;
  end
end

assign M_tag = M_tag_next;

// synthesis translate_off
always @(posedge clock)
begin
  if(m_axi_bresp != 0 || m_axi_rresp !=0)
  begin
    $display("ERROR: Sim: Abort incorret AXI answer from slave ");
    $finish;
  end
end
// synthesis translate_on

assign m_axi_arlen = 0;
assign m_axi_arburst = BURST_TYPE;
assign m_axi_arlock = 0;
assign m_axi_arcache = 0;
